import{D as e,S as t,c as n,d as r,h as i,k as a,m as o,p as s,t as c,w as l}from"./_plugin-vue_export-helper-27s0czD-.js";import{t as u}from"./gsap-BLz99MWe.js";var d={class:`terms-page`},f={class:`terms-content gsap-card`},p={class:`terms-footer`},m=c({__name:`TermsPage`,setup(c){return t(()=>{u.from(`.gsap-header`,{y:-30,opacity:0,duration:.8,ease:`power3.out`}),u.from(`.gsap-card`,{y:40,opacity:0,duration:.8,stagger:.15,ease:`power3.out`,delay:.2})}),(t,c)=>{let u=e(`router-link`);return l(),r(`div`,d,[c[2]||=n(`div`,{class:`page-header gsap-header`},[n(`div`,{class:`header-content`},[n(`h1`,null,`Terms and Conditions`),n(`p`,null,`Last updated: January 2026`)])],-1),n(`div`,f,[c[1]||=s(`<nav class="terms-nav" data-v-7b8bb495><ul data-v-7b8bb495><li data-v-7b8bb495><a href="#service" data-v-7b8bb495>Service Description</a></li><li data-v-7b8bb495><a href="#responsibilities" data-v-7b8bb495>User Responsibilities</a></li><li data-v-7b8bb495><a href="#immutability" data-v-7b8bb495>Blockchain Immutability</a></li><li data-v-7b8bb495><a href="#warranty" data-v-7b8bb495>No Warranty</a></li><li data-v-7b8bb495><a href="#privacy" data-v-7b8bb495>Privacy Policy</a></li><li data-v-7b8bb495><a href="#governing" data-v-7b8bb495>Governing Law</a></li></ul></nav><div class="terms-body" data-v-7b8bb495><section id="intro" data-v-7b8bb495><p class="intro-text" data-v-7b8bb495> Welcome to Provena. By using our document notarization services, you agree to these Terms and Conditions. Please read them carefully before using our platform. </p></section><section id="service" data-v-7b8bb495><h2 data-v-7b8bb495>1. Service Description</h2><p data-v-7b8bb495> Provena provides a decentralized document notarization service that creates cryptographic proofs anchored to the Bitcoin Cash (BCH) blockchain. Our service allows you to: </p><ul data-v-7b8bb495><li data-v-7b8bb495>Generate SHA-256 cryptographic hashes of your documents</li><li data-v-7b8bb495>Anchor document hashes to the Bitcoin Cash blockchain via OP_RETURN transactions</li><li data-v-7b8bb495>Verify document authenticity against blockchain records</li><li data-v-7b8bb495>Generate temporary verification links for third-party proof sharing</li></ul><div class="highlight-box" data-v-7b8bb495><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" data-v-7b8bb495><circle cx="12" cy="12" r="10" data-v-7b8bb495></circle><line x1="12" y1="8" x2="12" y2="12" data-v-7b8bb495></line><line x1="12" y1="16" x2="12.01" y2="16" data-v-7b8bb495></line></svg><p data-v-7b8bb495><strong data-v-7b8bb495>Important:</strong> Provena does not store your original documents unless you explicitly choose to upload them to our servers. Only cryptographic hashes are permanently recorded on the blockchain.</p></div></section><section id="responsibilities" data-v-7b8bb495><h2 data-v-7b8bb495>2. User Responsibilities</h2><p data-v-7b8bb495>By using Provena, you acknowledge and agree to the following:</p><h3 data-v-7b8bb495>2.1 Document Ownership</h3><p data-v-7b8bb495> You represent that you have the legal right to notarize any document you submit to our service. You warrant that your use of Provena does not violate any applicable laws, regulations, or third-party rights. </p><h3 data-v-7b8bb495>2.2 Private Key Custody</h3><p data-v-7b8bb495> Provena connects to your wallet through WizardConnect (Paytaca). You are solely responsible for: </p><ul data-v-7b8bb495><li data-v-7b8bb495>Securing your wallet credentials and private keys</li><li data-v-7b8bb495>Authorizing transactions through your wallet application</li><li data-v-7b8bb495>Maintaining access to your wallet for future verification purposes</li></ul><p data-v-7b8bb495> Provena does not have access to your private keys and cannot reverse or modify transactions once confirmed on the blockchain. </p><h3 data-v-7b8bb495>2.3 Transaction Fees</h3><p data-v-7b8bb495> Each notarization requires a small amount of Bitcoin Cash to pay network transaction fees. You are responsible for maintaining sufficient BCH balance in your connected wallet to complete notarizations. </p></section><section id="immutability" data-v-7b8bb495><h2 data-v-7b8bb495>3. Blockchain Immutability Disclaimer</h2><div class="warning-box" data-v-7b8bb495><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" data-v-7b8bb495><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z" data-v-7b8bb495></path><line x1="12" y1="9" x2="12" y2="13" data-v-7b8bb495></line><line x1="12" y1="17" x2="12.01" y2="17" data-v-7b8bb495></line></svg><div data-v-7b8bb495><p data-v-7b8bb495><strong data-v-7b8bb495>Irreversible Action:</strong> Once a document hash is anchored to the Bitcoin Cash blockchain, it cannot be removed, modified, or deleted. This is fundamental to blockchain technology and applies to all transactions, including those made through Provena.</p></div></div><p data-v-7b8bb495> By using our service, you understand and accept that: </p><ul data-v-7b8bb495><li data-v-7b8bb495>Blockchain transactions are permanent and cannot be undone</li><li data-v-7b8bb495>The cryptographic hash of your document will be publicly visible on the blockchain forever</li><li data-v-7b8bb495>Anyone with access to the blockchain can verify that a document with that hash existed at the time of notarization</li><li data-v-7b8bb495>Provena cannot delete or alter blockchain records under any circumstances</li></ul><p data-v-7b8bb495> Do not use Provena to notarize documents containing sensitive personal information if you may need such records removed in the future. </p></section><section id="warranty" data-v-7b8bb495><h2 data-v-7b8bb495>4. No Warranty</h2><p data-v-7b8bb495> PROVENA IS PROVIDED &quot;AS IS&quot; AND &quot;AS AVAILABLE&quot; WITHOUT WARRANTIES OF ANY KIND, EITHER EXPRESS OR IMPLIED, INCLUDING BUT NOT LIMITED TO: </p><ul data-v-7b8bb495><li data-v-7b8bb495>Warranties of merchantability or fitness for a particular purpose</li><li data-v-7b8bb495>Guarantees that the service will be uninterrupted, timely, or error-free</li><li data-v-7b8bb495>Guarantees regarding the accuracy or reliability of results</li></ul><h3 data-v-7b8bb495>4.1 Network Dependencies</h3><p data-v-7b8bb495> Our service relies on third-party infrastructure including: </p><ul data-v-7b8bb495><li data-v-7b8bb495><strong data-v-7b8bb495>Bitcoin Cash Network:</strong> Transaction confirmation times depend on network congestion and miner activity</li><li data-v-7b8bb495><strong data-v-7b8bb495>Watchtower API:</strong> Balance checks and UTXO queries depend on Paytaca&#39;s Watchtower service</li><li data-v-7b8bb495><strong data-v-7b8bb495>Block Explorers:</strong> Verification lookups depend on external blockchain explorer APIs</li></ul><p data-v-7b8bb495> We are not responsible for delays, failures, or inaccuracies caused by these external services. </p><h3 data-v-7b8bb495>4.2 Service Availability</h3><p data-v-7b8bb495> We do not guarantee 24/7 availability of our servers or API endpoints. Scheduled and unscheduled maintenance may temporarily interrupt service. </p></section><section id="privacy" data-v-7b8bb495><h2 data-v-7b8bb495>5. Privacy Policy Summary</h2><p data-v-7b8bb495> We are committed to protecting your privacy. Key aspects of our data handling: </p><h3 data-v-7b8bb495>5.1 Document Hashes</h3><p data-v-7b8bb495> Cryptographic hashes of your documents are permanently recorded on the public Bitcoin Cash blockchain. This is the core functionality of our service and cannot be avoided. </p><h3 data-v-7b8bb495>5.2 Document Storage</h3><p data-v-7b8bb495> Original documents are <strong data-v-7b8bb495>not stored by default</strong>. If you choose the optional &quot;Store file on server&quot; feature: </p><ul data-v-7b8bb495><li data-v-7b8bb495>Files are stored unencrypted on our servers</li><li data-v-7b8bb495>Files are associated with their blockchain record via temporary access tokens</li><li data-v-7b8bb495>Files may be deleted after extended periods of inactivity</li><li data-v-7b8bb495>We recommend using this feature only for non-sensitive documents</li></ul><h3 data-v-7b8bb495>5.3 Personal Information</h3><p data-v-7b8bb495> We do not require accounts or collect personal information. Email addresses provided for notifications are used solely for sending confirmation emails and are not stored permanently. </p><h3 data-v-7b8bb495>5.4 Wallet Information</h3><p data-v-7b8bb495> Your wallet connection (via WizardConnect) reveals your public BCH address. This is necessary for transaction signing and is public information already visible on the blockchain. </p><h3 data-v-7b8bb495>5.5 Analytics</h3><p data-v-7b8bb495> We may collect anonymous usage statistics to improve our service, including page views, feature usage, and error rates. </p></section><section id="governing" data-v-7b8bb495><h2 data-v-7b8bb495>6. Governing Law</h2><p data-v-7b8bb495> These Terms and Conditions shall be governed by and construed in accordance with the laws of [Jurisdiction Placeholder], without regard to its conflict of law provisions. </p><p data-v-7b8bb495> Any disputes arising from or related to these terms shall be resolved through binding arbitration in [Jurisdiction Placeholder], or in the courts of [Jurisdiction Placeholder] if arbitration is not applicable. </p></section><section id="changes" data-v-7b8bb495><h2 data-v-7b8bb495>7. Changes to Terms</h2><p data-v-7b8bb495> We reserve the right to modify these Terms and Conditions at any time. Changes will be posted on this page with an updated &quot;Last updated&quot; date. Continued use of Provena after changes constitutes acceptance of the revised terms. </p></section><section id="contact" data-v-7b8bb495><h2 data-v-7b8bb495>8. Contact Information</h2><p data-v-7b8bb495> For questions about these Terms and Conditions or our service, please contact us through: </p><ul data-v-7b8bb495><li data-v-7b8bb495>GitHub: <a href="https://github.com/provena" target="_blank" rel="noopener" data-v-7b8bb495>github.com/provena</a></li><li data-v-7b8bb495>Twitter: <a href="https://twitter.com/provena" target="_blank" rel="noopener" data-v-7b8bb495>@provena</a></li></ul></section></div>`,2),n(`div`,p,[i(u,{to:`/`,class:`back-link`},{default:a(()=>[...c[0]||=[n(`svg`,{width:`14`,height:`14`,viewBox:`0 0 24 24`,fill:`none`,stroke:`currentColor`,"stroke-width":`2`},[n(`line`,{x1:`19`,y1:`12`,x2:`5`,y2:`12`}),n(`polyline`,{points:`12 19 5 12 12 5`})],-1),o(` Back to Home `,-1)]]),_:1})])])])}}},[[`__scopeId`,`data-v-7b8bb495`]]);export{m as default};